import{_ as t,o as a,c as o,a3 as r}from"./chunks/framework.CjquFG0V.js";const p=JSON.parse('{"title":"How To Search","description":"","frontmatter":{},"headers":[],"relativePath":"about/how-to-search.md","filePath":"about/how-to-search.md"}'),s={name:"about/how-to-search.md"};function h(l,e,n,d,i,c){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="how-to-search" tabindex="-1">How To Search <a class="header-anchor" href="#how-to-search" aria-label="Permalink to &quot;How To Search&quot;">​</a></h1><p>Type any word or phrase into the search box at the top of the page. Results are ranked by relevance and each hit shows the matching passage with highlights.</p><p>Every clause page carries a hidden list of plain-language synonyms. You can search using everyday words and still find the relevant clause. For example:</p><table><thead><tr><th>If you search for</th><th>You&#39;ll find</th></tr></thead><tbody><tr><td>&quot;sick day&quot;, &quot;off crook&quot;</td><td>Personal Leave</td></tr><tr><td>&quot;time off for a funeral&quot;</td><td>Compassionate Leave / Ceremonial Leave</td></tr><tr><td>&quot;after hours phone calls&quot;</td><td>Right to Disconnect</td></tr><tr><td>&quot;called back to work&quot;</td><td>Recall to Duty / Overtime</td></tr></tbody></table><p>Prefix a term with a tag-like phrase to narrow results:</p><ul><li><code>leave eba:mental-health</code> finds leave clauses in the Mental Health EBA only.</li><li><code>overtime group:nurses</code> finds overtime clauses applicable to nurses.</li></ul><p>The default search does <strong>not</strong> include superseded or expired EBAs. If you need to look up historical entitlements (for example to interpret something that happened before a new EBA took effect), use the <a href="C:/Projects/tebooth92.github.io/archive/search" target="_blank" rel="noreferrer">archive search</a>.</p>',7)])])}const f=t(s,[["render",h]]);export{p as __pageData,f as default};
